+}
+
+fn bench_pagerank(c: &mut Criterion) {
+    let mut group = c.benchmark_group("pagerank");
+    for &n in &[50, 100, 500] {
+        let g = build_path(n);
+        group.bench_with_input(BenchmarkId::new("path", n), &n, |b, _| {
